package jp.co.createlink.core.rest;

import jp.co.createlink.core.exception.CoreException;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;
import org.springframework.web.reactive.function.client.WebClient;
import org.springframework.web.reactive.function.client.WebClientResponseException;

import java.time.Duration;
import java.util.Map;

/**
 * SampleRestClient
 *
 * <p>Spring WebClient を使った REST 接続クライアントのテンプレートクラス。</p>
 *
 * <p>このクラスは「接続パターンの見本」として設計されている。新規 REST システムに
 * 接続する際は、このクラスをコピーして以下を変更すること:</p>
 * <ol>
 *   <li>クラス名を接続先システム名に合わせる（例: {@code HogeSystemRestClient}）</li>
 *   <li>{@code @Value} のプロパティキーを {@code application-core.yml} に合わせる</li>
 *   <li>メソッドを OpenAPI 定義に沿った実装に書き換える</li>
 *   <li>レスポンス型を接続先の DTO に合わせる</li>
 * </ol>
 *
 * <h2>WebClient 選定理由</h2>
 * <ul>
 *   <li>Spring 5 以降の推奨 REST クライアント（RestTemplate は非推奨方向）</li>
 *   <li>リアクティブ（非同期）・同期の両方をサポート</li>
 *   <li>タイムアウト・リトライ・SSL 設定が柔軟</li>
 * </ul>
 *
 * <h2>同期呼び出しパターン</h2>
 * <p>このテンプレートでは {@code .block()} を使った同期呼び出しパターンを採用する。
 * Process-API が同期処理前提の場合はこのパターンが最もシンプル。
 * リアクティブ（非同期）パターンに変更する場合は {@code .block()} を外し、
 * 戻り値を {@code Mono<T>} / {@code Flux<T>} に変更すること。</p>
 */
@Component
public class SampleRestClient {

    /**
     * デフォルトのタイムアウト時間（秒）。
     * 接続先システムの応答時間に合わせて調整すること。
     */
    private static final Duration DEFAULT_TIMEOUT = Duration.ofSeconds(30);

    /**
     * WebClient インスタンス。
     * {@link #SampleRestClient(WebClient.Builder, String)} でベース URL を設定して生成する。
     */
    private final WebClient webClient;

    /**
     * コンストラクタ。
     *
     * <p>Spring の DI コンテナから {@link WebClient.Builder} を受け取り、
     * ベース URL を設定した {@link WebClient} インスタンスを生成する。</p>
     *
     * <p>{@link WebClient.Builder} は {@link jp.co.createlink.core.config.CoreConfig} で
     * Bean として定義されており、共通の SSL 設定・タイムアウト設定が適用されている。</p>
     *
     * @param webClientBuilder Spring が提供する {@link WebClient.Builder}（CoreConfig.java で定義）
     * @param baseUrl          接続先 REST API のベース URL（application-core.yml から注入）
     */
    public SampleRestClient(
            WebClient.Builder webClientBuilder,
            // ▼ プロパティキーは application-core.yml に合わせて変更すること
            @Value("${core.rest.sample.base-url:http://localhost:8080}") String baseUrl
    ) {
        // ベース URL を設定して WebClient インスタンスを生成する
        // ベース URL はクラス単位で固定し、各メソッドでパスを追加するパターン
        this.webClient = webClientBuilder
                .baseUrl(baseUrl)
                .build();
    }

    // ============================================================
    // GET メソッドのサンプル
    // ============================================================

    /**
     * サンプルデータを1件取得する（GET）。
     *
     * <p>OpenAPI 定義の {@code GET /samples/{id}} に対応するサンプルメソッド。
     * 新規実装時はこのメソッドをコピーして:</p>
     * <ol>
     *   <li>パス・クエリパラメータを接続先の OpenAPI 定義に合わせる</li>
     *   <li>戻り値の型を接続先 DTO に合わせる</li>
     *   <li>エラーハンドリングを接続先のエラーレスポンスに合わせる</li>
     * </ol>
     *
     * @param id 取得対象のリソース ID
     * @return レスポンスボディを {@code Map} で返す（実装時は接続先の DTO に変更すること）
     * @throws CoreException 通信エラーまたは接続先からのエラーレスポンス時にスロー
     */
    @SuppressWarnings("unchecked")
    public Map<String, Object> getSampleData(String id) {
        try {
            // .retrieve(): レスポンスを取得する（4xx/5xx は自動的に WebClientResponseException に変換）
            // .bodyToMono(): レスポンスボディを指定の型で受け取る
            // .block(timeout): 同期呼び出し（リアクティブパターンに変更する場合は .block() を外す）
            return webClient.get()
                    // ▼ パスは OpenAPI 定義に合わせて変更すること
                    .uri("/samples/{id}", id)
                    .retrieve()
                    // ▼ 戻り値の型は接続先の DTO クラスに変更すること（例: SampleResponse.class）
                    .bodyToMono(Map.class)
                    .block(DEFAULT_TIMEOUT);
        } catch (WebClientResponseException e) {
            // 接続先から 4xx / 5xx のエラーレスポンスが返った場合
            // ▼ エラーハンドリングは接続先のエラーレスポンス仕様に合わせて変更すること
            throw new CoreException(
                    "REST接続エラー: GET /samples/" + id
                            + " status=" + e.getStatusCode()
                            + " body=" + e.getResponseBodyAsString(),
                    e
            );
        } catch (Exception e) {
            // ネットワーク障害・タイムアウト等
            throw new CoreException("REST接続エラー: GET /samples/" + id, e);
        }
    }

    // ============================================================
    // POST メソッドのサンプル
    // ============================================================

    /**
     * サンプルデータを登録する（POST）。
     *
     * <p>OpenAPI 定義の {@code POST /samples} に対応するサンプルメソッド。
     * リクエストボディを JSON として送信し、登録結果を受け取る。</p>
     *
     * @param requestBody リクエストボディ（実装時は接続先のリクエスト DTO クラスに変更すること）
     * @return レスポンスボディを {@code Map} で返す（実装時は接続先のレスポンス DTO に変更すること）
     * @throws CoreException 通信エラーまたは接続先からのエラーレスポンス時にスロー
     */
    @SuppressWarnings("unchecked")
    public Map<String, Object> postSampleData(Map<String, Object> requestBody) {
        try {
            return webClient.post()
                    // ▼ パスは OpenAPI 定義に合わせて変更すること
                    .uri("/samples")
                    // リクエストボディを JSON として送信する
                    // ▼ bodyValue() の引数は接続先のリクエスト DTO オブジェクトに変更すること
                    .bodyValue(requestBody)
                    .retrieve()
                    // ▼ 戻り値の型は接続先のレスポンス DTO クラスに変更すること
                    .bodyToMono(Map.class)
                    .block(DEFAULT_TIMEOUT);
        } catch (WebClientResponseException e) {
            throw new CoreException(
                    "REST接続エラー: POST /samples"
                            + " status=" + e.getStatusCode()
                            + " body=" + e.getResponseBodyAsString(),
                    e
            );
        } catch (Exception e) {
            throw new CoreException("REST接続エラー: POST /samples", e);
        }
    }
}

package jp.co.createlink.core.exception;

/**
 * CoreException
 *
 * <p>Coreライブラリ全体の共通例外クラス。</p>
 *
 * <p>以下のケースで使用する:</p>
 * <ul>
 *   <li>REST 接続エラー（タイムアウト、接続拒否、4xx/5xx レスポンス等）</li>
 *   <li>SOAP 接続エラー（{@link SoapClientException} のラップも可）</li>
 *   <li>設定値の不正（必須プロパティ未設定等）</li>
 *   <li>その他 Core ライブラリ内部の処理エラー</li>
 * </ul>
 *
 * <h2>Process-API での使い方</h2>
 * <p>Process-API の {@code @ControllerAdvice}（GlobalExceptionHandler）で
 * このクラスをキャッチして適切な HTTP レスポンス（例: 502 Bad Gateway）に変換すること。</p>
 *
 * <h2>エラーコードの設計方針</h2>
 * <p>エラーコードは接続先システム・エラー種別を識別するための文字列。
 * 例: {@code "REST_SAMPLE_001"} / {@code "SOAP_SAMPLE_002"} のように
 * {@code "{プロトコル}_{システム名}_{連番}"} の形式を推奨する。</p>
 *
 * <h2>SoapClientException との使い分け</h2>
 * <ul>
 *   <li>{@code SoapClientException}: SOAP クライアント固有のエラー（既存・後方互換のため残す）</li>
 *   <li>{@code CoreException}: REST + SOAP 両方をカバーする汎用例外（新規実装で使用を推奨）</li>
 * </ul>
 */
public class CoreException extends RuntimeException {

    /**
     * エラーコード。
     * 接続先システムやエラー種別を識別するための文字列。
     * エラーコードが不要な場合は {@code null} を指定する。
     *
     * 例: "REST_SAMPLE_404" / "SOAP_HOGESYSTEM_TIMEOUT" / "CONFIG_MISSING_URL"
     */
    private final String errorCode;

    // ============================================================
    // コンストラクタ
    // ============================================================

    /**
     * メッセージのみ指定するコンストラクタ。
     *
     * <p>エラーコードが不要な場合に使用する。</p>
     *
     * @param message エラーメッセージ（人間が読める形式で記述すること）
     */
    public CoreException(String message) {
        super(message);
        this.errorCode = null;
    }

    /**
     * メッセージと原因例外を指定するコンストラクタ。
     *
     * <p>外部システムとの通信エラーをラップする場合に使用する。
     * 原因例外のスタックトレースが保持されるため、デバッグに役立つ。</p>
     *
     * @param message エラーメッセージ
     * @param cause   原因例外（WebClientResponseException / JAX-WS 例外等）
     */
    public CoreException(String message, Throwable cause) {
        super(message, cause);
        this.errorCode = null;
    }

    /**
     * エラーコード・メッセージを指定するコンストラクタ。
     *
     * <p>Process-API の GlobalExceptionHandler でエラーコードを使って
     * レスポンスを制御したい場合に使用する。</p>
     *
     * @param errorCode エラーコード（例: "REST_SAMPLE_404"）
     * @param message   エラーメッセージ
     */
    public CoreException(String errorCode, String message) {
        super(message);
        this.errorCode = errorCode;
    }

    /**
     * エラーコード・メッセージ・原因例外を指定するコンストラクタ。
     *
     * <p>最も情報量が多いコンストラクタ。外部システムとの通信エラーをラップしつつ
     * エラーコードも付与する場合に使用する。</p>
     *
     * @param errorCode エラーコード（例: "REST_SAMPLE_500"）
     * @param message   エラーメッセージ
     * @param cause     原因例外
     */
    public CoreException(String errorCode, String message, Throwable cause) {
        super(message, cause);
        this.errorCode = errorCode;
    }

    // ============================================================
    // ゲッター
    // ============================================================

    /**
     * エラーコードを返す。
     *
     * @return エラーコード。コンストラクタで指定しなかった場合は {@code null}
     */
    public String getErrorCode() {
        return errorCode;
    }

    /**
     * エラーコードが設定されているかどうかを返す。
     *
     * @return エラーコードが {@code null} でない場合 {@code true}
     */
    public boolean hasErrorCode() {
        return errorCode != null;
    }
}

package jp.co.createlink.core.config;

import io.netty.channel.ChannelOption;
import io.netty.handler.timeout.ReadTimeoutHandler;
import io.netty.handler.timeout.WriteTimeoutHandler;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.client.reactive.ReactorClientHttpConnector;
import org.springframework.web.reactive.function.client.WebClient;
import reactor.netty.http.client.HttpClient;
import reactor.netty.tcp.SslProvider;

import javax.net.ssl.TrustManagerFactory;
import java.io.FileInputStream;
import java.io.IOException;
import java.security.KeyStore;
import java.security.KeyStoreException;
import java.security.NoSuchAlgorithmException;
import java.security.cert.CertificateException;
import java.time.Duration;
import java.util.concurrent.TimeUnit;

/**
 * CoreConfig
 *
 * <p>Coreライブラリの共通設定クラス。</p>
 *
 * <p>このクラスでは以下の共通設定を行う:</p>
 * <ul>
 *   <li>{@link WebClient.Builder} Bean の定義（SSL・タイムアウト設定込み）</li>
 *   <li>共通設定値（タイムアウト、SSL等）の集約管理</li>
 * </ul>
 *
 * <h2>Process-API での使い方</h2>
 * <p>Process-API の Spring Boot アプリケーションに Core JAR を依存関係として追加すると、
 * このクラスが自動的に Bean 登録される（コンポーネントスキャンまたは {@code @Import} を使用）。
 * {@link WebClient.Builder} はこのクラスで定義した Bean が注入されるため、
 * 各 REST クライアントクラスで共通設定を意識せず WebClient を使用できる。</p>
 *
 * <h2>設定値の注入元</h2>
 * <p>{@code application-core.yml} に定義した {@code core.*} プロパティが
 * {@link Value} アノテーションで注入される。</p>
 *
 * <h2>SSL設定</h2>
 * <p>デフォルトはシステム標準の TrustStore を使用する。
 * 企業プロキシ等で独自CA証明書が必要な場合は {@code core.ssl.trust-store-path} を設定すること。</p>
 */
@Configuration
public class CoreConfig {

    // ============================================================
    // 設定値（application-core.yml から注入）
    // ============================================================

    /**
     * HTTP 接続確立のタイムアウト（ミリ秒）。
     * デフォルト: 5000ms（5秒）
     */
    @Value("${core.rest.connect-timeout-ms:5000}")
    private int connectTimeoutMs;

    /**
     * HTTP レスポンス読み取りのタイムアウト（秒）。
     * デフォルト: 30秒
     */
    @Value("${core.rest.read-timeout-sec:30}")
    private int readTimeoutSec;

    /**
     * HTTP リクエスト書き込みのタイムアウト（秒）。
     * デフォルト: 30秒
     */
    @Value("${core.rest.write-timeout-sec:30}")
    private int writeTimeoutSec;

    /**
     * カスタム TrustStore ファイルパス（オプション）。
     * 企業プロキシ等の独自CA証明書が必要な場合に設定する。
     * 未設定の場合はシステム標準の TrustStore を使用する。
     * デフォルト: 空文字（未設定扱い）
     */
    @Value("${core.ssl.trust-store-path:}")
    private String trustStorePath;

    /**
     * カスタム TrustStore のパスワード。
     * {@code core.ssl.trust-store-path} を設定した場合に必要。
     * デフォルト: "changeit"（JDK デフォルトの cacerts パスワード）
     */
    @Value("${core.ssl.trust-store-password:changeit}")
    private String trustStorePassword;

    // ============================================================
    // Bean 定義
    // ============================================================

    /**
     * WebClient.Builder Bean を定義する。
     *
     * <p>以下の設定を適用した {@link WebClient.Builder} を返す:</p>
     * <ul>
     *   <li>接続タイムアウト（{@code core.rest.connect-timeout-ms}）</li>
     *   <li>読み取りタイムアウト（{@code core.rest.read-timeout-sec}）</li>
     *   <li>書き込みタイムアウト（{@code core.rest.write-timeout-sec}）</li>
     *   <li>SSL 設定（カスタム TrustStore または JVM デフォルト）</li>
     * </ul>
     *
     * <p>各 REST クライアントクラスはこの Bean を DI で受け取り、
     * ベース URL を設定して {@link WebClient} インスタンスを生成する。</p>
     *
     * @return タイムアウト・SSL 設定済みの {@link WebClient.Builder}
     */
    @Bean
    public WebClient.Builder webClientBuilder() {
        // Reactor Netty の HttpClient でタイムアウト・SSL を設定する
        HttpClient httpClient = buildHttpClient();

        return WebClient.builder()
                // Reactor Netty をベースの HTTP クライアントとして設定する
                .clientConnector(new ReactorClientHttpConnector(httpClient));
    }

    // ============================================================
    // 内部メソッド
    // ============================================================

    /**
     * タイムアウト・SSL 設定を適用した {@link HttpClient} を生成する。
     *
     * <p>{@code core.ssl.trust-store-path} が設定されている場合はカスタム TrustStore を使用し、
     * 未設定の場合はシステム標準の TrustStore を使用する。</p>
     *
     * @return 設定済みの {@link HttpClient}
     */
    private HttpClient buildHttpClient() {
        HttpClient httpClient = HttpClient.create()
                // 接続確立タイムアウト（TCP 接続が完了するまでの時間）
                .option(ChannelOption.CONNECT_TIMEOUT_MILLIS, connectTimeoutMs)
                // レスポンス受信完了後の処理（読み取り・書き込みタイムアウト設定）
                .doOnConnected(conn -> conn
                        // 読み取りタイムアウト: サーバーからの応答を待つ最大時間
                        .addHandlerLast(new ReadTimeoutHandler(readTimeoutSec, TimeUnit.SECONDS))
                        // 書き込みタイムアウト: サーバーへのリクエスト送信完了までの最大時間
                        .addHandlerLast(new WriteTimeoutHandler(writeTimeoutSec, TimeUnit.SECONDS))
                );

        // ▼ カスタム TrustStore が設定されている場合は SSL 設定を適用する
        if (trustStorePath != null && !trustStorePath.isEmpty()) {
            httpClient = applyCustomSsl(httpClient);
        }
        // カスタム TrustStore が未設定の場合は JVM デフォルトの cacerts を使用する
        // （何もしなければ Reactor Netty は JVM のデフォルト TrustStore を使用する）

        return httpClient;
    }

    /**
     * カスタム TrustStore を使った SSL 設定を HttpClient に適用する。
     *
     * <p>企業プロキシ（例: Netskope, Zscaler）等の独自CA証明書が必要な環境で使用する。
     * {@code core.ssl.trust-store-path} に JKS または PKCS12 形式の TrustStore のパスを設定すること。</p>
     *
     * @param httpClient SSL 設定前の {@link HttpClient}
     * @return SSL 設定済みの {@link HttpClient}
     * @throws IllegalStateException TrustStore の読み込みに失敗した場合
     */
    private HttpClient applyCustomSsl(HttpClient httpClient) {
        try {
            // TrustStore を読み込む（JKS / PKCS12 形式に対応）
            // ▼ TrustStore 形式は接続先環境に合わせて変更すること
            KeyStore trustStore = KeyStore.getInstance(KeyStore.getDefaultType());
            try (FileInputStream fis = new FileInputStream(trustStorePath)) {
                trustStore.load(fis, trustStorePassword.toCharArray());
            }

            // TrustManagerFactory を初期化する
            TrustManagerFactory trustManagerFactory = TrustManagerFactory.getInstance(
                    TrustManagerFactory.getDefaultAlgorithm()
            );
            trustManagerFactory.init(trustStore);

            // SSL コンテキストを設定した HttpClient を返す
            return httpClient.secure(spec ->
                    spec.sslContext(
                            io.netty.handler.ssl.SslContextBuilder
                                    .forClient()
                                    .trustManager(trustManagerFactory)
                                    .build()
                    )
            );
        } catch (KeyStoreException | NoSuchAlgorithmException | CertificateException | IOException e) {
            // TrustStore の読み込みに失敗した場合はアプリ起動を中止する
            throw new IllegalStateException(
                    "カスタム TrustStore の読み込みに失敗しました: " + trustStorePath, e
            );
        } catch (Exception e) {
            throw new IllegalStateException(
                    "SSL設定の適用に失敗しました: " + trustStorePath, e
            );
        }
    }
}

