    // ソースレベルで参照される。MavenローカルへのPublishは不要。
    //
    // ■ Composite Buildでの参照方法
    //   project(":core") ではなく "group:artifact" 形式で指定する。
    //   Composite Buildではincluded buildのgroup/versionを使って参照する。
    //   core側のbuild.gradle.ktsのgroup="jp.co.createlink", version="1.0.0-SNAPSHOT"
    //   と一致させる必要がある。
    //
    // Coreが提供するもの:
    //   - SampleSoapClient: SOAP接続クライアント雛形
    //   - SampleRestClient: REST接続クライアント雛形
    //   - CoreConfig: WebClient.BuilderのBean設定
    //   - CoreException: 共通例外クラス
    // ----------------------------------------------------------------
    implementation("jp.co.createlink:core")

    // ----------------------------------------------------------------
    // テスト依存関係
    // spring-boot-starter-test にはJUnit 5、Mockito、MockMvcが含まれる
    // ----------------------------------------------------------------
    testImplementation("org.springframework.boot:spring-boot-starter-test")
}

// ============================================================
// テスト設定
// ============================================================
tasks.withType<Test> {
    // JUnit Platform (JUnit 5) を使用してテストを実行する
    useJUnitPlatform()

    // Java 21環境でMockitoが動的エージェントをロードする際の警告を抑制する
    jvmArgs("-XX:+EnableDynamicAgentLoading")
}

package jp.co.createlink.core.soap;

import jakarta.xml.ws.BindingProvider;
import jp.co.createlink.core.exception.SoapClientException;
import jp.co.createlink.core.soap.generated.GetSampleDataRequest;
import jp.co.createlink.core.soap.generated.GetSampleDataResponse;
import jp.co.createlink.core.soap.generated.SampleService;
import jp.co.createlink.core.soap.generated.SampleServicePortType;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;

import java.net.URL;

/**
 * SampleSoapClient
 *
 * <p>JAX-WS wsimport で生成されたスタブコードを利用した SOAP 接続クライアントのサンプル実装。
 * 新規 SOAP システム接続時は、このクラスを参考にしてクライアントクラスを実装すること。</p>
 *
 * <h2>新規SOAPシステム接続時の実装手順</h2>
 * <ol>
 *   <li>接続先の WSDL を {@code specs/wsdl/} に配置する</li>
 *   <li>{@code ./gradlew generateSoapSources} でスタブコードを生成する</li>
 *   <li>このクラスを参考にして {@code src/main/java/jp/co/createlink/core/soap/} に
 *       クライアントクラスを作成する</li>
 *   <li>{@code src/main/resources/application-core.yml} にエンドポイント URL を追加する</li>
 *   <li>Process-API の Service クラスから DI でクライアントを使用する</li>
 * </ol>
 *
 * <h2>パッケージ構成</h2>
 * <ul>
 *   <li>{@code soap/} - SOAP 接続クライアントを配置する（このクラス）</li>
 *   <li>{@code soap/generated/} - wsimport が自動生成したスタブクラス（手動編集禁止）</li>
 * </ul>
 *
 * @see SampleServicePortType 接続先サービスのインターフェース（wsimport生成）
 * @see SampleService JAX-WS サービスファクトリ（wsimport生成）
 */
@Component  // Spring DI コンテナに登録する。Process-API から @Autowired で注入可能。
public class SampleSoapClient {

    /**
     * SOAP エンドポイント URL。
     *
     * <p>ハードコードせず、application-core.yml から @Value で注入する。
     * 環境ごとに異なる URL を設定できるようにするため。</p>
     *
     * <p>▼ application-core.yml に以下を追加すること:</p>
     * <pre>
     * core:
     *   soap:
     *     sample:
     *       endpoint-url: http://target-system.example.com/soap/sample
     * </pre>
     *
     * <p>▼ 新規SOAPシステム接続時は、プロパティ名をシステムに合わせて変更すること。</p>
     */
    @Value("${core.soap.sample.endpoint-url:http://localhost:8080/soap/sample}")
    private String endpointUrl;

    /**
     * SOAP ポート（スタブインターフェース）。
     * {@link #createPort()} で初期化する。
     * @see #createPort()
     */
    private SampleServicePortType port;

    /**
     * デフォルトコンストラクタ。
     * Spring DI コンテナが @Component を検出してインスタンス化する。
     */
    public SampleSoapClient() {
        // Spring DI 用デフォルトコンストラクタ
        // @Value の注入はコンストラクタ呼び出し後に実行されるため、
        // ポートの初期化は遅延初期化（createPort）で行う
    }

    /**
     * テスト用コンストラクタ。
     *
     * <p>単体テストでモックポートを注入するために使用する。
     * 本番コードでは Spring DI によりデフォルトコンストラクタが使用される。</p>
     *
     * @param endpointUrl SOAP エンドポイント URL
     * @param port        モックポート（テスト用）
     */
    SampleSoapClient(String endpointUrl, SampleServicePortType port) {
        this.endpointUrl = endpointUrl;
        this.port = port;
    }

    /**
     * サンプルデータ取得。
     *
     * <p>SOAP 接続のサンプルオペレーション。wsimport が生成した {@link SampleServicePortType}
     * インターフェースのメソッドを呼び出すパターンを示す。</p>
     *
     * <p>新規SOAPシステム接続時は、このメソッドを参考にして接続先のオペレーションに
     * 対応したメソッドを実装すること。</p>
     *
     * <h3>実装パターン</h3>
     * <ol>
     *   <li>リクエストオブジェクトを生成してパラメータをセットする</li>
     *   <li>ポート（スタブ）を取得する（初回はポートを生成、以降は再利用）</li>
     *   <li>ポートのメソッドを呼び出してレスポンスを取得する</li>
     *   <li>レスポンスのステータスコードを確認してエラーハンドリングを行う</li>
     * </ol>
     *
     * @param id 取得対象のID（接続先システムのキー項目）
     * @return SOAP レスポンス
     * @throws SoapClientException SOAP 通信エラーまたは接続先エラーレスポンスの場合
     */
    public GetSampleDataResponse getSampleData(String id) {
        // ▼ 1. リクエストオブジェクトを生成してパラメータをセットする
        //      接続先のオペレーションに合わせてリクエストクラスを変更すること
        GetSampleDataRequest request = new GetSampleDataRequest();
        request.setId(id);

        // ▼ 2. ポート（スタブ）を取得する
        //      getOrCreatePort() は遅延初期化で endpointUrl を反映したポートを返す
        SampleServicePortType soapPort = getOrCreatePort();

        try {
            // ▼ 3. ポートのメソッドを呼び出してレスポンスを取得する
            //      接続先のオペレーション名に合わせてメソッドを変更すること
            GetSampleDataResponse response = soapPort.getSampleData(request);

            // ▼ 4. レスポンスのステータスコードを確認する
            //      接続先のエラーコード定義に合わせて条件を変更すること
            if (response == null) {
                throw new SoapClientException("SOAP レスポンスが null でした。id=" + id);
            }
            if (!"0".equals(response.getStatusCode())) {
                throw new SoapClientException(
                        String.format("SOAP エラーレスポンス: statusCode=%s, message=%s",
                                response.getStatusCode(), response.getMessage()));
            }

            return response;

        } catch (SoapClientException e) {
            // アプリケーション例外はそのまま再スローする
            throw e;
        } catch (Exception e) {
            // JAX-WS の通信エラー（タイムアウト、接続拒否等）をアプリケーション例外にラップする
            throw new SoapClientException("SOAP 通信エラーが発生しました: " + e.getMessage(), e);
        }
    }

    /**
     * SOAP ポートを生成する。
     *
     * <p>JAX-WS の {@link SampleService}（wsimport生成）から
     * {@link SampleServicePortType} ポートを取得し、
     * エンドポイント URL を {@link BindingProvider} 経由で上書きする。</p>
     *
     * <p>これにより、WSDL に記述されたデフォルト URL の代わりに
     * application-core.yml で設定した URL に接続できる。</p>
     *
     * <p>▼ 新規SOAPシステム接続時のポイント:</p>
     * <ul>
     *   <li>{@link SampleService} を接続先の Service クラスに変更する</li>
     *   <li>WSDL URL は classpathリソースまたはファイルパスを指定する</li>
     * </ul>
     *
     * @return エンドポイント URL が設定済みの SOAP ポート
     */
    private SampleServicePortType createPort() {
        try {
            // WSDL をクラスパスリソースから読み込む。
            // ▼ 新規SOAPシステム接続時は WSDL のパスを変更すること
            URL wsdlUrl = SampleSoapClient.class
                    .getClassLoader()
                    .getResource("wsdl/sample-service.wsdl");

            if (wsdlUrl == null) {
                // WSDL が classpath に存在しない場合は specs/ ディレクトリを参照する（開発時）
                // 本番環境ではビルド時にリソースとしてパッケージングすること
                throw new SoapClientException("WSDL リソースが見つかりません: wsdl/sample-service.wsdl");
            }

            // JAX-WS Service からポートを取得する
            // ▼ 接続先の Service クラスに変更すること（wsimport生成）
            SampleService service = new SampleService(wsdlUrl);
            SampleServicePortType createdPort = service.getSampleServicePort();

            // エンドポイント URL を application-core.yml の設定値で上書きする
            // WSDL に記述された URL はデフォルト値として使用し、
            // 実際の接続先は設定ファイルから注入する
            BindingProvider bindingProvider = (BindingProvider) createdPort;
            bindingProvider.getRequestContext()
                    .put(BindingProvider.ENDPOINT_ADDRESS_PROPERTY, endpointUrl);

            return createdPort;

        } catch (SoapClientException e) {
            throw e;
        } catch (Exception e) {
            throw new SoapClientException("SOAP ポートの初期化に失敗しました: " + e.getMessage(), e);
        }
    }

    /**
     * ポートの遅延初期化と取得。
     *
     * <p>初回呼び出し時に {@link #createPort()} でポートを生成する。
     * 2回目以降は同じポートインスタンスを再利用する（非スレッドセーフ）。</p>
     *
     * <p>スレッドセーフが必要な場合は synchronized を付与するか、
     * Spring の @Scope("prototype") を使用してリクエストごとに別インスタンスを生成すること。</p>
     *
     * @return SOAP ポート
     */
    private SampleServicePortType getOrCreatePort() {
        if (port == null) {
            port = createPort();
        }
        return port;
    }

    /**
     * エンドポイント URL を取得する（テスト・デバッグ用）。
     *
     * @return 設定されているエンドポイント URL
     */
    public String getEndpointUrl() {
        return endpointUrl;
    }
}

package jp.co.createlink.core.rest;

import jp.co.createlink.core.exception.CoreException;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;
import org.springframework.web.reactive.function.client.WebClient;
import org.springframework.web.reactive.function.client.WebClientResponseException;

import java.time.Duration;
import java.util.Map;

/**
 * SampleRestClient
 *
 * <p>Spring WebClient を使った REST 接続クライアントのテンプレートクラス。</p>
 *
 * <p>このクラスは「接続パターンの見本」として設計されている。新規 REST システムに
 * 接続する際は、このクラスをコピーして以下を変更すること:</p>
 * <ol>
 *   <li>クラス名を接続先システム名に合わせる（例: {@code HogeSystemRestClient}）</li>
 *   <li>{@code @Value} のプロパティキーを {@code application-core.yml} に合わせる</li>
 *   <li>メソッドを OpenAPI 定義に沿った実装に書き換える</li>
 *   <li>レスポンス型を接続先の DTO に合わせる</li>
 * </ol>
 *
 * <h2>WebClient 選定理由</h2>
 * <ul>
 *   <li>Spring 5 以降の推奨 REST クライアント（RestTemplate は非推奨方向）</li>
 *   <li>リアクティブ（非同期）・同期の両方をサポート</li>
 *   <li>タイムアウト・リトライ・SSL 設定が柔軟</li>
 * </ul>
 *
 * <h2>同期呼び出しパターン</h2>
 * <p>このテンプレートでは {@code .block()} を使った同期呼び出しパターンを採用する。
 * Process-API が同期処理前提の場合はこのパターンが最もシンプル。
 * リアクティブ（非同期）パターンに変更する場合は {@code .block()} を外し、
 * 戻り値を {@code Mono<T>} / {@code Flux<T>} に変更すること。</p>
 */
@Component
public class SampleRestClient {

    /**
     * デフォルトのタイムアウト時間（秒）。
     * 接続先システムの応答時間に合わせて調整すること。
     */
    private static final Duration DEFAULT_TIMEOUT = Duration.ofSeconds(30);

    /**
     * WebClient インスタンス。
     * {@link #SampleRestClient(WebClient.Builder, String)} でベース URL を設定して生成する。
     */
    private final WebClient webClient;

    /**
     * コンストラクタ。
     *
     * <p>Spring の DI コンテナから {@link WebClient.Builder} を受け取り、
     * ベース URL を設定した {@link WebClient} インスタンスを生成する。</p>
     *
     * <p>{@link WebClient.Builder} は {@link jp.co.createlink.core.config.CoreConfig} で
     * Bean として定義されており、共通の SSL 設定・タイムアウト設定が適用されている。</p>
     *
     * @param webClientBuilder Spring が提供する {@link WebClient.Builder}（CoreConfig.java で定義）
     * @param baseUrl          接続先 REST API のベース URL（application-core.yml から注入）
     */
    public SampleRestClient(
            WebClient.Builder webClientBuilder,
            // ▼ プロパティキーは application-core.yml に合わせて変更すること
            @Value("${core.rest.sample.base-url:http://localhost:8080}") String baseUrl
    ) {
        // ベース URL を設定して WebClient インスタンスを生成する
        // ベース URL はクラス単位で固定し、各メソッドでパスを追加するパターン
        this.webClient = webClientBuilder
                .baseUrl(baseUrl)
                .build();
    }

    // ============================================================
    // GET メソッドのサンプル
    // ============================================================

    public Map<String, Object> getSampleData(String id) {
        try {
            // .retrieve(): レスポンスを取得する（4xx/5xx は自動的に WebClientResponseException に変換）
            // .bodyToMono(): レスポンスボディを指定の型で受け取る
            // .block(timeout): 同期呼び出し（リアクティブパターンに変更する場合は .block() を外す）
            return webClient.get()
                    // ▼ パスは OpenAPI 定義に合わせて変更すること
                    .uri("/samples/{id}", id)
                    .retrieve()
                    // ▼ 戻り値の型は接続先の DTO クラスに変更すること（例: SampleResponse.class）
                    .bodyToMono(Map.class)
                    .block(DEFAULT_TIMEOUT);
        } catch (WebClientResponseException e) {
            // 接続先から 4xx / 5xx のエラーレスポンスが返った場合
            // ▼ エラーハンドリングは接続先のエラーレスポンス仕様に合わせて変更すること
            throw new CoreException(
                    "REST接続エラー: GET /samples/" + id
                            + " status=" + e.getStatusCode()
                            + " body=" + e.getResponseBodyAsString(),
                    e
            );
        } catch (Exception e) {
            // ネットワーク障害・タイムアウト等
            throw new CoreException("REST接続エラー: GET /samples/" + id, e);
        }
    }

    // ============================================================
    // POST メソッドのサンプル
    // ============================================================

--
    public Map<String, Object> postSampleData(Map<String, Object> requestBody) {
        try {
            return webClient.post()
                    // ▼ パスは OpenAPI 定義に合わせて変更すること
                    .uri("/samples")
                    // リクエストボディを JSON として送信する
                    // ▼ bodyValue() の引数は接続先のリクエスト DTO オブジェクトに変更すること
                    .bodyValue(requestBody)
                    .retrieve()
                    // ▼ 戻り値の型は接続先のレスポンス DTO クラスに変更すること
                    .bodyToMono(Map.class)
                    .block(DEFAULT_TIMEOUT);
        } catch (WebClientResponseException e) {
            throw new CoreException(
                    "REST接続エラー: POST /samples"
                            + " status=" + e.getStatusCode()
                            + " body=" + e.getResponseBodyAsString(),
                    e
            );
        } catch (Exception e) {
            throw new CoreException("REST接続エラー: POST /samples", e);
        }
    }
}

package jp.co.createlink.core.exception;

/**
 * CoreException
 *
 * <p>Coreライブラリ全体の共通例外クラス。</p>
 *
 * <p>以下のケースで使用する:</p>
 * <ul>
 *   <li>REST 接続エラー（タイムアウト、接続拒否、4xx/5xx レスポンス等）</li>
 *   <li>SOAP 接続エラー（{@link SoapClientException} のラップも可）</li>
 *   <li>設定値の不正（必須プロパティ未設定等）</li>
 *   <li>その他 Core ライブラリ内部の処理エラー</li>
 * </ul>
 *
 * <h2>Process-API での使い方</h2>
 * <p>Process-API の {@code @ControllerAdvice}（GlobalExceptionHandler）で
 * このクラスをキャッチして適切な HTTP レスポンス（例: 502 Bad Gateway）に変換すること。</p>
 *
 * <h2>エラーコードの設計方針</h2>
 * <p>エラーコードは接続先システム・エラー種別を識別するための文字列。
 * 例: {@code "REST_SAMPLE_001"} / {@code "SOAP_SAMPLE_002"} のように
 * {@code "{プロトコル}_{システム名}_{連番}"} の形式を推奨する。</p>
 *
 * <h2>SoapClientException との使い分け</h2>
 * <ul>
 *   <li>{@code SoapClientException}: SOAP クライアント固有のエラー（既存・後方互換のため残す）</li>
 *   <li>{@code CoreException}: REST + SOAP 両方をカバーする汎用例外（新規実装で使用を推奨）</li>
 * </ul>
 */
public class CoreException extends RuntimeException {

    /**
     * エラーコード。
     * 接続先システムやエラー種別を識別するための文字列。
     * エラーコードが不要な場合は {@code null} を指定する。
     *
     * 例: "REST_SAMPLE_404" / "SOAP_HOGESYSTEM_TIMEOUT" / "CONFIG_MISSING_URL"
     */
    private final String errorCode;

    // ============================================================
    // コンストラクタ
    // ============================================================

    /**
     * メッセージのみ指定するコンストラクタ。
     *
     * <p>エラーコードが不要な場合に使用する。</p>
     *
     * @param message エラーメッセージ（人間が読める形式で記述すること）
     */
    public CoreException(String message) {
        super(message);
        this.errorCode = null;
    }

    /**
     * メッセージと原因例外を指定するコンストラクタ。
     *
     * <p>外部システムとの通信エラーをラップする場合に使用する。
     * 原因例外のスタックトレースが保持されるため、デバッグに役立つ。</p>
     *
     * @param message エラーメッセージ
     * @param cause   原因例外（WebClientResponseException / JAX-WS 例外等）
     */
    public CoreException(String message, Throwable cause) {
        super(message, cause);
        this.errorCode = null;
    }

    /**
     * エラーコード・メッセージを指定するコンストラクタ。
     *
     * <p>Process-API の GlobalExceptionHandler でエラーコードを使って
     * レスポンスを制御したい場合に使用する。</p>
     *
     * @param errorCode エラーコード（例: "REST_SAMPLE_404"）
     * @param message   エラーメッセージ
     */
    public CoreException(String errorCode, String message) {
        super(message);
        this.errorCode = errorCode;
    }

    /**
     * エラーコード・メッセージ・原因例外を指定するコンストラクタ。
     *
     * <p>最も情報量が多いコンストラクタ。外部システムとの通信エラーをラップしつつ
     * エラーコードも付与する場合に使用する。</p>
     *
     * @param errorCode エラーコード（例: "REST_SAMPLE_500"）
     * @param message   エラーメッセージ
     * @param cause     原因例外
     */
    public CoreException(String errorCode, String message, Throwable cause) {
        super(message, cause);
        this.errorCode = errorCode;
    }

    // ============================================================
    // ゲッター
    // ============================================================

    /**
     * エラーコードを返す。
     *
     * @return エラーコード。コンストラクタで指定しなかった場合は {@code null}
     */
    public String getErrorCode() {
        return errorCode;
    }

    /**
     * エラーコードが設定されているかどうかを返す。
     *
     * @return エラーコードが {@code null} でない場合 {@code true}
     */
    public boolean hasErrorCode() {
        return errorCode != null;
    }
}

