package jp.co.createlink.processapi.service;

import jp.co.createlink.core.exception.CoreException;
import jp.co.createlink.core.rest.SampleRestClient;
import jp.co.createlink.core.soap.SampleSoapClient;
import jp.co.createlink.processapi.dto.SampleResponse;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.NoSuchElementException;

/**
 * SampleService
 *
 * <p>サンプルAPIのサービスクラス。Controller から呼び出され、Core ライブラリ経由で
 * 社内システムからデータを取得する。</p>
 *
 * <h2>レイヤー責務</h2>
 * <ul>
 *   <li><b>Controller</b>: HTTPリクエスト/レスポンス処理、バリデーション</li>
 *   <li><b>Service（このクラス）</b>: ビジネスロジック、Coreクライアントの呼び出し</li>
 *   <li><b>Core</b>: 社内システムへの接続クライアント（SOAP/REST）</li>
 * </ul>
 *
 * <h2>新規ドメインAPI実装ガイド（VibeCoding用）</h2>
 * <ol>
 *   <li>このクラスをコピーして接続先システムに合わせたサービスクラスを作成する</li>
 *   <li>DI で Core ライブラリのクライアントを注入する（コンストラクタインジェクション推奨）</li>
 *   <li>ビジネスロジックに応じてメソッドを実装する</li>
 *   <li>Core クライアントが投げる {@link CoreException} は原則そのまま伝播させ、
 *       GlobalExceptionHandler で HTTP レスポンスに変換する</li>
 *   <li>データが存在しない場合は {@link NoSuchElementException} を投げ、
 *       GlobalExceptionHandler が 404 に変換する</li>
 * </ol>
 *
 * @see SampleRestClient REST接続クライアント（Coreライブラリ）
 * @see SampleSoapClient SOAP接続クライアント（Coreライブラリ）
 */
@Service  // Spring DI コンテナに登録する。Controller から @Autowired で注入可能。
public class SampleService {

    private static final Logger logger = LoggerFactory.getLogger(SampleService.class);

    /**
     * REST接続クライアント（Coreライブラリ）。
     * Core 経由でサンプルシステム（REST API）に接続する。
     *
     * <p>▼ 新規ドメイン実装時は、接続先システムに合わせた REST クライアントに変更すること。</p>
     */
    private final SampleRestClient sampleRestClient;

    /**
     * SOAP接続クライアント（Coreライブラリ）。
     * Core 経由でサンプルシステム（SOAP API）に接続する。
     *
     * <p>▼ 新規ドメイン実装時は、接続先システムに合わせた SOAP クライアントに変更すること。
     * SOAP 不要の場合はフィールドとコンストラクタ引数ごと削除する。</p>
     */
    private final SampleSoapClient sampleSoapClient;

    // ============================================================
    // コンストラクタ
    // ============================================================

    /**
     * コンストラクタ（コンストラクタインジェクション）。
     *
     * <p>Spring の DI コンテナが Core ライブラリの Bean を自動的に注入する。
     * {@code @Autowired} アノテーションは Spring 4.3 以降は単一コンストラクタの場合は省略可能。</p>
     *
     * <p>コンストラクタインジェクションを採用する理由:</p>
     * <ul>
     *   <li>フィールドが {@code final} にでき、不変性が保証される</li>
     *   <li>テスト時にモックを容易に注入できる</li>
     *   <li>必須依存関係が明確になる</li>
     * </ul>
     *
     * @param sampleRestClient REST接続クライアント（CoreライブラリのBean）
     * @param sampleSoapClient SOAP接続クライアント（CoreライブラリのBean）
     */
    public SampleService(SampleRestClient sampleRestClient, SampleSoapClient sampleSoapClient) {
        this.sampleRestClient = sampleRestClient;
        this.sampleSoapClient = sampleSoapClient;
    }

    // ============================================================
    // 公開メソッド
    // ============================================================

    /**
     * サンプルデータ一覧取得。
     *
     * <p>Core 経由でサンプルシステムからデータを取得し、レスポンスDTOのリストで返す。</p>
     *
     * <h3>実装パターン（テンプレート）</h3>
     * <p>このメソッドは、Core クライアントを呼び出してデータを取得し、
     * Process-API のレスポンスDTOに変換するパターンを示す。</p>
     *
     * <p>現在はスタブデータを返しているが、新規ドメイン実装時には
     * Core クライアントの呼び出しに置き換えること。</p>
     *
     * <h3>Core クライアント呼び出しパターン（VibeCoding向けコメント）</h3>
     * <pre>
     * // REST クライアント経由でデータ取得（非同期→同期パターン）
     * Map&lt;String, Object&gt; restData = sampleRestClient.getSampleData("list");
     *
     * // SOAP クライアント経由でデータ取得
     * GetSampleDataResponse soapResponse = sampleSoapClient.getSampleData("all");
     * </pre>
     *
     * @return サンプルデータ一覧（{@link SampleResponse} のリスト）
     * @throws CoreException Core ライブラリが社内システムへの接続に失敗した場合
     */
    public List<SampleResponse> getSampleList() {
        logger.info("サンプルデータ一覧取得を開始します");

        try {
            // ▼▼▼ ここをドメイン固有のロジックに変更すること ▼▼▼
            //
            // パターン1: Core の REST クライアントでデータ取得
            // Map<String, Object> restData = sampleRestClient.getSampleData("list");
            //
            // パターン2: Core の SOAP クライアントでデータ取得
            // GetSampleDataResponse soapResponse = sampleSoapClient.getSampleData("all");
            //
            // 現在はスタブデータを返す（接続先未確定の場合のテンプレートパターン）
            // ▼▼▼ ここまで ▼▼▼

            List<SampleResponse> samples = buildStubSampleList();

            logger.info("サンプルデータ一覧取得が完了しました。件数={}", samples.size());
            return samples;

        } catch (CoreException e) {
            // CoreException はそのまま再スローする。
            // GlobalExceptionHandler が 500 Internal Server Error に変換する。
            logger.error("Core経由でのデータ取得に失敗しました: {}", e.getMessage(), e);
            throw e;
        }
    }

    /**
     * 特定サンプルデータ取得。
     *
     * <p>指定された ID に対応するサンプルデータを Core 経由で取得して返す。</p>
     *
     * <p>現在はスタブデータを返しているが、新規ドメイン実装時には
     * Core クライアントの呼び出しに置き換えること。</p>
     *
     * <h3>Core クライアント呼び出しパターン（VibeCoding向けコメント）</h3>
     * <pre>
     * // REST クライアント経由でデータ取得
     * Map&lt;String, Object&gt; restData = sampleRestClient.getSampleData(id);
     * if (restData == null) {
     *     throw new NoSuchElementException("サンプルデータが見つかりません: id=" + id);
     * }
     *
     * // SOAP クライアント経由でデータ取得
     * GetSampleDataResponse soapResponse = sampleSoapClient.getSampleData(id);
     * </pre>
     *
     * @param id 取得対象のサンプルID
     * @return 指定IDのサンプルデータ
     * @throws NoSuchElementException 指定IDのデータが存在しない場合（HTTP 404 に変換される）
     * @throws CoreException          Core ライブラリが社内システムへの接続に失敗した場合（HTTP 500 に変換される）
     * @throws IllegalArgumentException IDが不正な場合（HTTP 400 に変換される）
     */
    public SampleResponse getSampleById(String id) {
        logger.info("サンプルデータ取得を開始します。id={}", id);

        // ▼ 入力値バリデーション（必要に応じてドメイン固有のルールに変更すること）
        if (id == null || id.isBlank()) {
            throw new IllegalArgumentException("IDは空にできません");
        }

        try {
            // ▼▼▼ ここをドメイン固有のロジックに変更すること ▼▼▼
            //
            // パターン1: Core の REST クライアントでデータ取得
            // Map<String, Object> restData = sampleRestClient.getSampleData(id);
            // if (restData == null) {
            //     throw new NoSuchElementException("サンプルデータが見つかりません: id=" + id);
            // }
            // return convertToSampleResponse(id, restData);
            //
            // パターン2: Core の SOAP クライアントでデータ取得
            // GetSampleDataResponse soapResponse = sampleSoapClient.getSampleData(id);
            // return convertSoapResponseToDto(soapResponse);
            //
            // 現在はスタブデータを返す（接続先未確定の場合のテンプレートパターン）
            // ▼▼▼ ここまで ▼▼▼

            SampleResponse sample = buildStubSampleById(id);

            logger.info("サンプルデータ取得が完了しました。id={}", id);
            return sample;

        } catch (NoSuchElementException | IllegalArgumentException e) {
            // バリデーションエラー・存在しないデータはそのまま再スローする。
            // GlobalExceptionHandler が 404 / 400 に変換する。
            throw e;
        } catch (CoreException e) {
            // CoreException はそのまま再スローする。
            // GlobalExceptionHandler が 500 Internal Server Error に変換する。
            logger.error("Core経由でのデータ取得に失敗しました: id={}, error={}", id, e.getMessage(), e);
            throw e;
        }
    }

    // ============================================================
    // プライベートメソッド（スタブデータ生成）
    // ============================================================

    /**
     * スタブの一覧データを生成する（テンプレート用）。
     *
     * <p>接続先システムへの実際の接続実装が完了するまでの仮データ。
     * 新規ドメイン実装時はこのメソッドを削除し、Core クライアント呼び出しに置き換えること。</p>
     *
     * @return スタブのサンプルデータ一覧
     */
    private List<SampleResponse> buildStubSampleList() {
        List<SampleResponse> list = new ArrayList<>();

        for (int i = 1; i <= 3; i++) {
            Map<String, Object> stubData = new HashMap<>();
            // ▼ スタブデータ: 実際の接続先システムのレスポンス形式に合わせて変更すること
            stubData.put("source", "stub");
            stubData.put("description", "Core経由で取得されるデータ（スタブ）");

            list.add(new SampleResponse(
                    "sample-00" + i,
                    "サンプルデータ " + i,
                    stubData
            ));
        }

        return list;
    }

    /**
     * スタブの特定IDデータを生成する（テンプレート用）。
     *
     * <p>接続先システムへの実際の接続実装が完了するまでの仮データ。
     * 新規ドメイン実装時はこのメソッドを削除し、Core クライアント呼び出しに置き換えること。</p>
     *
     * @param id 取得対象のID
     * @return スタブのサンプルデータ
     * @throws NoSuchElementException IDが "notfound" の場合（404 動作確認用）
     */
    private SampleResponse buildStubSampleById(String id) {
        // ▼ "notfound" を ID として渡すと 404 レスポンスを確認できる（デモ用）
        if ("notfound".equals(id)) {
            throw new NoSuchElementException("サンプルデータが見つかりません: id=" + id);
        }

        Map<String, Object> stubData = new HashMap<>();
        // ▼ スタブデータ: 実際の接続先システムのレスポンス形式に合わせて変更すること
        stubData.put("source", "stub");
        stubData.put("requestedId", id);
        stubData.put("description", "Core経由で取得されるデータ（スタブ）");

        return new SampleResponse(id, "サンプルデータ " + id, stubData);
    }
}

package jp.co.createlink.processapi.controller;

import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.Parameter;
import io.swagger.v3.oas.annotations.media.Content;
import io.swagger.v3.oas.annotations.media.Schema;
import io.swagger.v3.oas.annotations.responses.ApiResponse;
import io.swagger.v3.oas.annotations.responses.ApiResponses;
import io.swagger.v3.oas.annotations.tags.Tag;
import jp.co.createlink.processapi.dto.SampleResponse;
import jp.co.createlink.processapi.exception.ErrorResponse;
import jp.co.createlink.processapi.service.SampleService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;

/**
 * SampleController
 *
 * <p>サンプルAPIエンドポイントのコントローラークラス。
 * Core ライブラリ経由でデータを取得するパターンを示すテンプレート。</p>
 *
 * <h2>レイヤー責務</h2>
 * <ul>
 *   <li><b>Controller（このクラス）</b>: HTTPリクエスト/レスポンス処理、バリデーション</li>
 *   <li><b>Service</b>: ビジネスロジック、Coreクライアントの呼び出し</li>
 *   <li><b>Core</b>: 社内システムへの接続クライアント（SOAP/REST）</li>
 * </ul>
 *
 * <h2>新規ドメインAPI実装ガイド（VibeCoding用）</h2>
 * <ol>
 *   <li>このクラスをコピーして接続先システムに合わせたコントローラーを作成する</li>
 *   <li>{@code @RequestMapping} のパスをドメインに合わせて変更する</li>
 *   <li>{@code @Operation} 等のアノテーションを更新してSwagger UIに表示される説明を充実させる</li>
 *   <li>サービスクラスを DI で注入して呼び出す</li>
 * </ol>
 *
 * @see SampleService サービスクラス（Core経由のデータ取得ロジック）
 */
@RestController
@RequestMapping("/api/v1/sample")
@Tag(name = "Sample", description = "サンプルAPIエンドポイント（Core経由データ取得パターンのテンプレート）")
public class SampleController {

    private static final Logger logger = LoggerFactory.getLogger(SampleController.class);

    /**
     * サービスクラス（コンストラクタインジェクション）。
     * Spring の DI コンテナが自動的に Bean を注入する。
     */
    private final SampleService sampleService;

    // ============================================================
    // コンストラクタ
    // ============================================================

    /**
     * コンストラクタ（コンストラクタインジェクション）。
     *
     * <p>Spring の DI コンテナが {@link SampleService} を自動的に注入する。
     * {@code @Autowired} は単一コンストラクタの場合は省略可能（Spring 4.3以降）。</p>
     *
     * @param sampleService サービスクラス
     */
    public SampleController(SampleService sampleService) {
        this.sampleService = sampleService;
    }

    // ============================================================
    // エンドポイント
    // ============================================================

    /**
     * サンプルデータ一覧取得。
     *
     * <p>GET {@code /api/v1/sample}</p>
     *
     * <p>Core 経由でサンプルシステムからデータを取得し、一覧として返す。
     * エラーが発生した場合は {@link jp.co.createlink.processapi.exception.GlobalExceptionHandler}
     * が統一フォーマットのエラーレスポンスに変換する。</p>
     *
     * @return サンプルデータ一覧（200 OK）
     */
    @GetMapping
    @Operation(
            summary = "サンプルデータ一覧取得",
            description = "Core経由で社内システムからサンプルデータを取得する。"
                    + "Controller → Service → Core のレイヤー構成パターンのテンプレート。"
    )
    @ApiResponses(value = {
            @ApiResponse(
                    responseCode = "200",
                    description = "正常レスポンス",
                    content = @Content(
                            mediaType = "application/json",
                            schema = @Schema(implementation = SampleResponse.class)
                    )
            ),
            @ApiResponse(
                    responseCode = "500",
                    description = "サーバーエラー（Core経由の接続失敗等）",
                    content = @Content(
                            mediaType = "application/json",
                            schema = @Schema(implementation = ErrorResponse.class)
                    )
            )
    })
    public ResponseEntity<List<SampleResponse>> getSampleList() {
        logger.info("GET /api/v1/sample が呼び出されました");

        // ▼ Service を呼び出す。例外は GlobalExceptionHandler が処理する。
        List<SampleResponse> samples = sampleService.getSampleList();

        logger.info("GET /api/v1/sample が正常完了しました。件数={}", samples.size());
        return ResponseEntity.ok(samples);
    }

    /**
     * 特定サンプルデータ取得。
     *
     * <p>GET {@code /api/v1/sample/{id}}</p>
     *
     * <p>指定された ID のサンプルデータを Core 経由で取得して返す。
     * データが存在しない場合は 404 Not Found を返す。</p>
     *
     * <p>▼ 動作確認用: ID に "notfound" を指定すると 404 レスポンスを確認できる。</p>
     *
     * @param id 取得対象のサンプルID（パスパラメータ）
     * @return 指定IDのサンプルデータ（200 OK）
     */
    @GetMapping("/{id}")
    @Operation(
            summary = "サンプルデータ取得",
            description = "指定された ID のサンプルデータを Core 経由で取得する。"
                    + "存在しない ID を指定すると 404 Not Found を返す（動作確認用: id='notfound'）。"
    )
    @ApiResponses(value = {
            @ApiResponse(
                    responseCode = "200",
                    description = "正常レスポンス",
                    content = @Content(
                            mediaType = "application/json",
                            schema = @Schema(implementation = SampleResponse.class)
                    )
            ),
            @ApiResponse(
                    responseCode = "400",
                    description = "リクエストパラメータ不正",
                    content = @Content(
                            mediaType = "application/json",
                            schema = @Schema(implementation = ErrorResponse.class)
                    )
            ),
            @ApiResponse(
                    responseCode = "404",
                    description = "指定IDのデータが見つからない",
                    content = @Content(
                            mediaType = "application/json",
                            schema = @Schema(implementation = ErrorResponse.class)
                    )
            ),
            @ApiResponse(
                    responseCode = "500",
                    description = "サーバーエラー（Core経由の接続失敗等）",
                    content = @Content(
                            mediaType = "application/json",
                            schema = @Schema(implementation = ErrorResponse.class)
                    )
            )
    })
    public ResponseEntity<SampleResponse> getSampleById(
            @Parameter(description = "サンプルID（動作確認用: 'notfound' で 404 を確認できる）", required = true)
            @PathVariable String id
    ) {
        logger.info("GET /api/v1/sample/{} が呼び出されました", id);

        // ▼ Service を呼び出す。例外は GlobalExceptionHandler が処理する。
        SampleResponse sample = sampleService.getSampleById(id);

        logger.info("GET /api/v1/sample/{} が正常完了しました", id);
        return ResponseEntity.ok(sample);
    }
}

package jp.co.createlink.processapi.exception;

import com.fasterxml.jackson.annotation.JsonFormat;
import io.swagger.v3.oas.annotations.media.Schema;

import java.time.LocalDateTime;

/**
 * ErrorResponse
 *
 * <p>統一エラーレスポンスDTO。{@link GlobalExceptionHandler} がエラー発生時に返す JSON 形式を定義する。</p>
 *
 * <h2>レスポンス形式</h2>
 * <pre>
 * {
 *   "timestamp": "2026-04-10T10:00:00.000",
 *   "status": 500,
 *   "error": "Internal Server Error",
 *   "message": "社内システムへの接続に失敗しました",
 *   "path": "/api/v1/sample"
 * }
 * </pre>
 *
 * <h2>フィールド説明</h2>
 * <ul>
 *   <li>{@code timestamp}: エラー発生時刻</li>
 *   <li>{@code status}: HTTP ステータスコード（数値）</li>
 *   <li>{@code error}: HTTP ステータス名（文字列）</li>
 *   <li>{@code message}: エラーメッセージ（人間が読める形式）</li>
 *   <li>{@code path}: エラーが発生したリクエストパス</li>
 * </ul>
 *
 * @see GlobalExceptionHandler エラーハンドラー（このDTOを生成する）
 */
@Schema(description = "統一エラーレスポンス")
public class ErrorResponse {

    /**
     * エラー発生時刻。
     * ISO 8601 形式（yyyy-MM-dd'T'HH:mm:ss.SSS）でシリアライズされる。
     */
    @Schema(description = "エラー発生時刻", example = "2026-04-10T10:00:00.000")
    @JsonFormat(pattern = "yyyy-MM-dd'T'HH:mm:ss.SSS")
    private LocalDateTime timestamp;

    /**
     * HTTP ステータスコード（数値）。
     * 例: 400, 404, 500
     */
    @Schema(description = "HTTPステータスコード", example = "500")
    private int status;

    /**
     * HTTP ステータス名（文字列）。
     * 例: "Bad Request", "Not Found", "Internal Server Error"
     */
    @Schema(description = "HTTPステータス名", example = "Internal Server Error")
    private String error;

    /**
     * エラーメッセージ。
     * 人間が読める形式で記述する。
     */
    @Schema(description = "エラーメッセージ", example = "社内システムへの接続に失敗しました")
    private String message;

    /**
     * エラーが発生したリクエストパス。
     * {@link jakarta.servlet.http.HttpServletRequest#getRequestURI()} から取得する。
     */
    @Schema(description = "リクエストパス", example = "/api/v1/sample")
    private String path;

    // ============================================================
    // コンストラクタ
    // ============================================================

    /**
     * デフォルトコンストラクタ。
     * Jackson のデシリアライズに必要。
     */
    public ErrorResponse() {
    }

    /**
     * 全フィールドを設定するコンストラクタ。
     *
     * @param timestamp エラー発生時刻
     * @param status    HTTP ステータスコード
     * @param error     HTTP ステータス名
     * @param message   エラーメッセージ
     * @param path      リクエストパス
     */
    public ErrorResponse(LocalDateTime timestamp, int status, String error, String message, String path) {
        this.timestamp = timestamp;
        this.status = status;
        this.error = error;
        this.message = message;
        this.path = path;
    }

    // ============================================================
    // ゲッター・セッター
    // ============================================================

    /**
     * エラー発生時刻を返す。
     *
     * @return エラー発生時刻
     */
    public LocalDateTime getTimestamp() {
        return timestamp;
    }

    /**
     * エラー発生時刻を設定する。
     *
     * @param timestamp エラー発生時刻
     */
    public void setTimestamp(LocalDateTime timestamp) {
        this.timestamp = timestamp;
    }

    /**
     * HTTP ステータスコードを返す。
     *
     * @return HTTP ステータスコード
     */
    public int getStatus() {
        return status;
    }

    /**
     * HTTP ステータスコードを設定する。
     *
     * @param status HTTP ステータスコード
     */
    public void setStatus(int status) {
        this.status = status;
    }

    /**
     * HTTP ステータス名を返す。
     *
     * @return HTTP ステータス名
     */
    public String getError() {
        return error;
    }

    /**
     * HTTP ステータス名を設定する。
     *
     * @param error HTTP ステータス名
     */
    public void setError(String error) {
        this.error = error;
    }

    /**
     * エラーメッセージを返す。
     *
     * @return エラーメッセージ
     */
    public String getMessage() {
        return message;
    }

    /**
     * エラーメッセージを設定する。
     *
     * @param message エラーメッセージ
     */
    public void setMessage(String message) {
        this.message = message;
    }

    /**
     * リクエストパスを返す。
     *
     * @return リクエストパス
     */
    public String getPath() {
        return path;
    }

    /**
     * リクエストパスを設定する。
     *
     * @param path リクエストパス
     */
    public void setPath(String path) {
        this.path = path;
    }
}

package jp.co.createlink.processapi.exception;

import jakarta.servlet.http.HttpServletRequest;
import jp.co.createlink.core.exception.CoreException;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

import java.time.LocalDateTime;
import java.util.NoSuchElementException;

/**
 * GlobalExceptionHandler
 *
 * <p>Process-API 全体の例外を一元的に処理するコントローラーアドバイス。
 * 例外ごとに適切な HTTP ステータスコードと統一フォーマットの {@link ErrorResponse} を返す。</p>
 *
 * <h2>ハンドリング対象と HTTP ステータスの対応</h2>
 * <table border="1">
 *   <tr><th>例外</th><th>HTTP ステータス</th><th>用途</th></tr>
 *   <tr><td>{@link IllegalArgumentException}</td><td>400 Bad Request</td><td>入力値不正</td></tr>
 *   <tr><td>{@link NoSuchElementException}</td><td>404 Not Found</td><td>リソースが存在しない</td></tr>
 *   <tr><td>{@link CoreException}</td><td>500 Internal Server Error</td><td>社内システム接続エラー</td></tr>
 *   <tr><td>{@link Exception}（その他）</td><td>500 Internal Server Error</td><td>予期しないエラー</td></tr>
 * </table>
 *
 * <h2>使い方（VibeCoding用）</h2>
 * <p>Controller / Service で以下の例外を投げるだけで、このクラスが自動的に変換する:</p>
 * <ul>
 *   <li>入力値が不正: {@code throw new IllegalArgumentException("メッセージ")}</li>
 *   <li>リソースなし: {@code throw new NoSuchElementException("メッセージ")}</li>
 *   <li>Core接続エラー: Core クライアントが自動的に {@link CoreException} を投げる</li>
 * </ul>
 *
 * <h2>新規例外の追加方法</h2>
 * <ol>
 *   <li>新規の {@code @ExceptionHandler} メソッドを追加する</li>
 *   <li>{@link #buildErrorResponse(HttpStatus, String, HttpServletRequest)} を使って
 *       {@link ErrorResponse} を生成する</li>
 *   <li>適切な {@link HttpStatus} を設定して {@link ResponseEntity} で返す</li>
 * </ol>
 *
 * @see ErrorResponse 統一エラーレスポンスDTO
 */
@RestControllerAdvice  // @ControllerAdvice + @ResponseBody の組み合わせ。JSON レスポンスを自動で返す。
public class GlobalExceptionHandler {

    private static final Logger logger = LoggerFactory.getLogger(GlobalExceptionHandler.class);

    // ============================================================
    // 例外ハンドラー
    // ============================================================

    /**
     * Core ライブラリ例外ハンドラー（500 Internal Server Error）。
     *
     * <p>社内システムへの接続失敗（SOAP/REST タイムアウト、エラーレスポンス等）を
     * 500 Internal Server Error として返す。</p>
     *
     * <p>Core ライブラリが提供する {@link CoreException} は、すべての接続エラーを
     * ラップしているため、このメソッドで一元処理できる。</p>
     *
     * @param ex      発生した Core ライブラリ例外
     * @param request HTTP リクエスト情報（パス取得に使用）
     * @return 500 エラーレスポンス（統一フォーマット）
     */
    @ExceptionHandler(CoreException.class)
    public ResponseEntity<ErrorResponse> handleCoreException(
            CoreException ex,
            HttpServletRequest request
    ) {
        logger.error("Core例外が発生しました: path={}, errorCode={}, message={}",
                request.getRequestURI(), ex.getErrorCode(), ex.getMessage(), ex);

        ErrorResponse errorResponse = buildErrorResponse(
                HttpStatus.INTERNAL_SERVER_ERROR,
                "社内システムへの接続に失敗しました: " + ex.getMessage(),
                request
        );
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(errorResponse);
    }

    /**
     * 入力値不正例外ハンドラー（400 Bad Request）。
     *
     * <p>Controller / Service で入力値検証に失敗した場合に 400 Bad Request を返す。</p>
     *
     * <p>使用例（Service クラスでのバリデーション）:</p>
     * <pre>
     * if (id == null || id.isBlank()) {
     *     throw new IllegalArgumentException("IDは空にできません");
     * }
     * </pre>
     *
     * @param ex      発生した入力値不正例外
     * @param request HTTP リクエスト情報（パス取得に使用）
     * @return 400 エラーレスポンス（統一フォーマット）
     */
    @ExceptionHandler(IllegalArgumentException.class)
    public ResponseEntity<ErrorResponse> handleIllegalArgumentException(
            IllegalArgumentException ex,
            HttpServletRequest request
    ) {
        logger.warn("入力値不正例外が発生しました: path={}, message={}", request.getRequestURI(), ex.getMessage());

        ErrorResponse errorResponse = buildErrorResponse(
                HttpStatus.BAD_REQUEST,
                ex.getMessage(),
                request
        );
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(errorResponse);
    }

    /**
     * リソース未存在例外ハンドラー（404 Not Found）。
     *
     * <p>指定された ID のリソースが存在しない場合に 404 Not Found を返す。</p>
     *
     * <p>使用例（Service クラスでの存在チェック）:</p>
     * <pre>
     * if (data == null) {
     *     throw new NoSuchElementException("サンプルデータが見つかりません: id=" + id);
     * }
     * </pre>
     *
     * @param ex      発生したリソース未存在例外
     * @param request HTTP リクエスト情報（パス取得に使用）
     * @return 404 エラーレスポンス（統一フォーマット）
     */
    @ExceptionHandler(NoSuchElementException.class)
    public ResponseEntity<ErrorResponse> handleNoSuchElementException(
            NoSuchElementException ex,
            HttpServletRequest request
    ) {
        logger.warn("リソース未存在例外が発生しました: path={}, message={}", request.getRequestURI(), ex.getMessage());

        ErrorResponse errorResponse = buildErrorResponse(
                HttpStatus.NOT_FOUND,
                ex.getMessage(),
                request
        );
        return ResponseEntity.status(HttpStatus.NOT_FOUND).body(errorResponse);
    }

    /**
     * 汎用例外ハンドラー（500 Internal Server Error）。
     *
     * <p>上記のハンドラーで処理されなかった予期しない例外をキャッチして
     * 500 Internal Server Error を返す。</p>
     *
     * <p>スタックトレースをログに残すため、根本原因の調査に役立てること。</p>
     *
     * @param ex      発生した例外
     * @param request HTTP リクエスト情報（パス取得に使用）
     * @return 500 エラーレスポンス（統一フォーマット）
     */
    @ExceptionHandler(Exception.class)
    public ResponseEntity<ErrorResponse> handleGenericException(
            Exception ex,
            HttpServletRequest request
    ) {
        logger.error("予期しない例外が発生しました: path={}, exceptionType={}, message={}",
                request.getRequestURI(), ex.getClass().getName(), ex.getMessage(), ex);

        ErrorResponse errorResponse = buildErrorResponse(
                HttpStatus.INTERNAL_SERVER_ERROR,
                "内部サーバーエラーが発生しました",
                request
        );
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(errorResponse);
    }

    // ============================================================
    // プライベートメソッド
    // ============================================================

    /**
     * 統一フォーマットの {@link ErrorResponse} を生成する。
     *
     * <p>各 {@code @ExceptionHandler} メソッドから呼び出し、統一フォーマットで
     * エラーレスポンスを生成する。</p>
     *
     * @param status  HTTP ステータス
     * @param message エラーメッセージ
     * @param request HTTP リクエスト情報（パス取得に使用）
     * @return 統一フォーマットのエラーレスポンス
     */
    private ErrorResponse buildErrorResponse(HttpStatus status, String message, HttpServletRequest request) {
        return new ErrorResponse(
                LocalDateTime.now(),       // timestamp: エラー発生時刻
                status.value(),            // status: HTTP ステータスコード（数値）
                status.getReasonPhrase(),  // error: HTTP ステータス名（文字列）
                message,                   // message: エラーメッセージ
                request.getRequestURI()    // path: リクエストパス
        );
    }
}

