                .andExpect(jsonPath("$.message").value("サンプルデータが見つかりません: id=" + notFoundId))
                .andExpect(jsonPath("$.path").value("/api/v1/sample/" + notFoundId))
                .andExpect(jsonPath("$.timestamp").exists());
