package jp.co.createlink.processapi.service;

import jp.co.createlink.core.exception.CoreException;
import jp.co.createlink.core.rest.SampleRestClient;
import jp.co.createlink.core.soap.SampleSoapClient;
import jp.co.createlink.processapi.dto.SampleResponse;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import java.util.List;
import java.util.NoSuchElementException;

import static org.assertj.core.api.Assertions.*;
import static org.mockito.Mockito.*;

/**
 * 【モジュール】SampleService
 * SampleService のユニットテスト。
 * SampleRestClient と SampleSoapClient はモック化してサービスクラスのみをテストする。
 */
@ExtendWith(MockitoExtension.class)
class SampleServiceTest {

    /**
     * REST クライアントのモック。
     */
    @Mock
    private SampleRestClient sampleRestClient;

    /**
     * SOAP クライアントのモック。
     */
    @Mock
    private SampleSoapClient sampleSoapClient;

    /**
     * テスト対象のサービスクラス。
     */
    private SampleService sampleService;

    @BeforeEach
    void setUp() {
        sampleService = new SampleService(sampleRestClient, sampleSoapClient);
    }

    // ============================================================
    // getSampleList テスト
    // ============================================================

    /**
     * 【テスト対象】getSampleList()
     * 【テスト内容】正常系: スタブデータが返ること
     * 【期待結果】空でないリストが返り、各要素に id, name が設定されている
     */
    @Test
    void should_return_sample_list_successfully() {
        // Act
        List<SampleResponse> result = sampleService.getSampleList();

        // Assert
        assertThat(result).isNotNull();
        assertThat(result).isNotEmpty();
        assertThat(result).allSatisfy(sample -> {
            assertThat(sample.getId()).isNotNull().isNotBlank();
            assertThat(sample.getName()).isNotNull().isNotBlank();
        });
    }

    /**
     * 【テスト対象】getSampleList()
     * 【テスト内容】スタブデータの件数確認
     * 【期待結果】3件のスタブデータが返ること（テンプレートのデフォルト値）
     */
    @Test
    void should_return_three_stub_samples_in_list() {
        // Act
        List<SampleResponse> result = sampleService.getSampleList();

        // Assert: スタブデータは3件
        assertThat(result).hasSize(3);
        assertThat(result).extracting(SampleResponse::getId)
                .containsExactly("sample-001", "sample-002", "sample-003");
    }

    // ============================================================
    // getSampleById テスト
    // ============================================================

    /**
     * 【テスト対象】getSampleById(String id)
     * 【テスト内容】正常系: 有効な ID でデータが返ること
     * 【期待結果】指定した ID に対応する SampleResponse が返る
     */
    @Test
    void should_return_sample_when_valid_id_provided() {
        // Arrange
        String id = "sample-001";

        // Act
        SampleResponse result = sampleService.getSampleById(id);

        // Assert
        assertThat(result).isNotNull();
        assertThat(result.getId()).isEqualTo(id);
        assertThat(result.getName()).isNotNull().isNotBlank();
    }

    /**
     * 【テスト対象】getSampleById(String id)
     * 【テスト内容】異常系: "notfound" ID を指定した場合
     * 【期待結果】NoSuchElementException が投げられる（HTTP 404 に変換される）
     *
     * 【前提条件】"notfound" は 404 動作確認用の特殊 ID
     */
    @Test
    void should_throw_NoSuchElementException_when_id_is_notfound() {
        // Act & Assert
        assertThatThrownBy(() -> sampleService.getSampleById("notfound"))
                .isInstanceOf(NoSuchElementException.class)
                .hasMessageContaining("notfound");
    }

    /**
     * 【テスト対象】getSampleById(String id)
     * 【テスト内容】異常系: null ID を指定した場合
     * 【期待結果】IllegalArgumentException が投げられる（HTTP 400 に変換される）
     */
    @Test
    void should_throw_IllegalArgumentException_when_id_is_null() {
        // Act & Assert
        assertThatThrownBy(() -> sampleService.getSampleById(null))
                .isInstanceOf(IllegalArgumentException.class)
                .hasMessageContaining("空にできません");
    }

    /**
     * 【テスト対象】getSampleById(String id)
     * 【テスト内容】異常系: 空文字 ID を指定した場合
     * 【期待結果】IllegalArgumentException が投げられる（HTTP 400 に変換される）
     */
    @Test
    void should_throw_IllegalArgumentException_when_id_is_blank() {
        // Act & Assert
        assertThatThrownBy(() -> sampleService.getSampleById("  "))
                .isInstanceOf(IllegalArgumentException.class)
                .hasMessageContaining("空にできません");
    }

    /**
     * 【テスト対象】getSampleById(String id)
     * 【テスト内容】Core ライブラリが CoreException を投げた場合の伝播確認
     * 【期待結果】CoreException がそのまま伝播する（GlobalExceptionHandler が 500 に変換する）
     *
     * 【前提条件】getSampleList() で CoreException が発生した場合を再現するため、
     *            この テストでは サービスクラスを直接サブクラス化して例外を強制発生させる
     */
    @Test
    void should_propagate_CoreException_when_core_throws_exception() {
        // CoreException を投げるサービスのサブクラスを作成して検証
        SampleService serviceWithException = new SampleService(sampleRestClient, sampleSoapClient) {
            @Override
            public List<SampleResponse> getSampleList() {
                throw new CoreException("REST_SAMPLE_500", "接続失敗");
            }
        };

        // Act & Assert
        assertThatThrownBy(serviceWithException::getSampleList)
                .isInstanceOf(CoreException.class)
                .hasMessageContaining("接続失敗");
    }
}

package jp.co.createlink.processapi.exception;

import jp.co.createlink.core.exception.CoreException;
import jp.co.createlink.processapi.controller.SampleController;
import jp.co.createlink.processapi.service.SampleService;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.test.context.bean.override.mockito.MockitoBean;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;

import java.util.NoSuchElementException;

import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

/**
 * 【モジュール】GlobalExceptionHandler
 * GlobalExceptionHandler のユニットテスト。
 * 各例外に対して統一エラーフォーマットが返ることを検証する。
 */
@WebMvcTest(controllers = {SampleController.class, GlobalExceptionHandler.class})
class GlobalExceptionHandlerTest {

    @Autowired
    private MockMvc mockMvc;

    @MockitoBean
    private SampleService sampleService;

    /**
     * 【テスト対象】@ExceptionHandler(CoreException.class)
     * 【テスト内容】Core ライブラリが CoreException を投げた場合
     * 【期待結果】HTTP 500 Internal Server Error、統一エラーフォーマット（全フィールド存在）
     */
    @Test
    void should_return_500_with_error_response_when_CoreException_thrown() throws Exception {
        // Arrange: CoreException を投げるモック設定
        when(sampleService.getSampleList())
                .thenThrow(new CoreException("REST_001", "社内システムへの接続に失敗しました"));

        // Act & Assert: 500 と統一エラーフォーマットを検証
        mockMvc.perform(get("/api/v1/sample")
                        .accept(MediaType.APPLICATION_JSON))
                .andExpect(status().isInternalServerError())
                .andExpect(content().contentTypeCompatibleWith(MediaType.APPLICATION_JSON))
                .andExpect(jsonPath("$.status").value(500))
                .andExpect(jsonPath("$.error").value("Internal Server Error"))
                .andExpect(jsonPath("$.message").exists())
                .andExpect(jsonPath("$.path").value("/api/v1/sample"))
                .andExpect(jsonPath("$.timestamp").exists());
    }

    /**
     * 【テスト対象】@ExceptionHandler(IllegalArgumentException.class)
     * 【テスト内容】Service が IllegalArgumentException を投げた場合
     * 【期待結果】HTTP 400 Bad Request、統一エラーフォーマット
     */
    @Test
    void should_return_400_with_error_response_when_IllegalArgumentException_thrown() throws Exception {
        // Arrange
        when(sampleService.getSampleById("bad-id"))
                .thenThrow(new IllegalArgumentException("IDの形式が不正です"));

        // Act & Assert
        mockMvc.perform(get("/api/v1/sample/{id}", "bad-id")
                        .accept(MediaType.APPLICATION_JSON))
                .andExpect(status().isBadRequest())
                .andExpect(jsonPath("$.status").value(400))
                .andExpect(jsonPath("$.error").value("Bad Request"))
                .andExpect(jsonPath("$.message").value("IDの形式が不正です"))
                .andExpect(jsonPath("$.path").value("/api/v1/sample/bad-id"))
                .andExpect(jsonPath("$.timestamp").exists());
    }

    /**
     * 【テスト対象】@ExceptionHandler(NoSuchElementException.class)
     * 【テスト内容】Service が NoSuchElementException を投げた場合
     * 【期待結果】HTTP 404 Not Found、統一エラーフォーマット
     */
    @Test
    void should_return_404_with_error_response_when_NoSuchElementException_thrown() throws Exception {
        // Arrange
        when(sampleService.getSampleById("notfound"))
                .thenThrow(new NoSuchElementException("サンプルデータが見つかりません: id=notfound"));

        // Act & Assert
        mockMvc.perform(get("/api/v1/sample/{id}", "notfound")
                        .accept(MediaType.APPLICATION_JSON))
                .andExpect(status().isNotFound())
                .andExpect(jsonPath("$.status").value(404))
                .andExpect(jsonPath("$.error").value("Not Found"))
                .andExpect(jsonPath("$.message").value("サンプルデータが見つかりません: id=notfound"))
                .andExpect(jsonPath("$.path").value("/api/v1/sample/notfound"))
                .andExpect(jsonPath("$.timestamp").exists());
    }

    /**
     * 【テスト対象】@ExceptionHandler(Exception.class)
     * 【テスト内容】予期しない例外が発生した場合
     * 【期待結果】HTTP 500 Internal Server Error、統一エラーフォーマット（一般的なメッセージ）
     */
    @Test
    void should_return_500_with_generic_message_when_unexpected_exception_thrown() throws Exception {
        // Arrange: RuntimeException（予期しない例外）を投げるモック設定
        when(sampleService.getSampleList())
                .thenThrow(new RuntimeException("予期しないエラー"));

        // Act & Assert
        mockMvc.perform(get("/api/v1/sample")
                        .accept(MediaType.APPLICATION_JSON))
                .andExpect(status().isInternalServerError())
                .andExpect(jsonPath("$.status").value(500))
                .andExpect(jsonPath("$.error").value("Internal Server Error"))
                // 汎用例外ハンドラーは詳細メッセージを隠すことで情報漏洩を防ぐ
                .andExpect(jsonPath("$.message").value("内部サーバーエラーが発生しました"))
                .andExpect(jsonPath("$.timestamp").exists());
    }
}

